// MultiSelect.tsx (reuses TagInput from rn-108 for chips)
import React, {useState} from 'react';
import {View, Pressable, Text, ScrollView} from 'react-native';
import {TagInput} from './TagInput';
export function MultiSelect({options}: {options: string[]}) { const [selected, setSelected] = useState<string[]>([]); return (<View><TagInput tags={selected} onChange={setSelected}/><ScrollView>{options.filter(o => !selected.includes(o)).map(o => (<Pressable key={o} onPress={() => setSelected(s => [...s, o])}><Text style={{color:'#fff', padding:8}}>{o}</Text></Pressable>))}</ScrollView></View>); }

